use serde::{Deserialize, Serialize};
use specta::Type;
use uuid::Uuid;

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct AgentConfig {
    pub tool_name: String,
    pub sub_agent_count: u32,
    pub is_master: bool,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct OrchestratorConfig {
    pub agents: Vec<AgentConfig>,
    pub master_agent: String,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct SubTask {
    pub id: String,
    pub prompt: String,
    pub assigned_agent: String,
    pub status: String,
    pub parent_task_id: String,
    #[serde(default)]
    pub depends_on: Vec<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct OrchestrationPlan {
    pub task_id: String,
    pub original_prompt: String,
    pub sub_tasks: Vec<SubTask>,
    pub master_agent: String,
    pub phase: OrchestrationPhase,
    pub decomposition: Option<DecompositionResult>,
    pub worker_results: Vec<WorkerResult>,
    pub master_process_id: Option<String>,
}

#[derive(Debug, Clone, Serialize, Type)]
pub struct AgentContextInfo {
    pub tool_name: String,
    pub input_tokens: Option<u32>,
    pub output_tokens: Option<u32>,
    pub total_tokens: Option<u32>,
    pub cost_usd: Option<f64>,
    pub status: String,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type, PartialEq)]
pub enum OrchestrationPhase {
    Decomposing,
    AwaitingApproval,
    Executing,
    WaitingForInput,
    Reviewing,
    Completed,
    Failed,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct DecompositionResult {
    pub tasks: Vec<SubTaskDef>,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct SubTaskDef {
    #[serde(default)]
    pub id: Option<String>,
    pub agent: String,
    pub prompt: String,
    pub description: String,
    #[serde(default)]
    pub depends_on: Vec<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize, Type)]
pub struct WorkerResult {
    pub task_id: String,
    pub agent: String,
    pub exit_code: i32,
    pub output_summary: String, // last N lines of output
    #[serde(default)]
    pub retry_count: u32,
    #[serde(default)]
    pub original_agent: Option<String>,
    #[serde(default)]
    pub failure_reason: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PendingQuestion {
    pub question: crate::adapters::Question,
    pub worker_task_id: String,
    pub plan_id: String,
}

pub struct Orchestrator;

impl Orchestrator {
    /// Create an orchestration plan shell. Sub-tasks are populated later by
    /// `dispatch_orchestrated_task` after the master agent decomposes the task.
    pub fn create_plan(prompt: &str, config: &OrchestratorConfig) -> OrchestrationPlan {
        OrchestrationPlan {
            task_id: Uuid::new_v4().to_string(),
            original_prompt: prompt.to_string(),
            sub_tasks: Vec::new(),
            master_agent: config.master_agent.clone(),
            phase: OrchestrationPhase::Decomposing,
            decomposition: None,
            worker_results: Vec::new(),
            master_process_id: None,
        }
    }

    /// Build a prompt that asks the master agent to decompose a task into sub-tasks
    /// and return strict JSON output.
    pub fn build_decompose_prompt(prompt: &str, available_agents: &[AgentConfig]) -> String {
        let agent_list: Vec<String> = available_agents
            .iter()
            .map(|a| format!("- \"{}\"", a.tool_name))
            .collect();

        format!(
            "You are a task orchestrator. Your ONLY job is to return a JSON task plan.\n\n\
             Available agents:\n{}\n\n\
             User request: {}\n\n\
             INSTRUCTIONS:\n\
             - You MUST return ONLY a JSON object. No greetings, no explanations, no markdown.\n\
             - If the request is simple, conversational, or a single task, return it as ONE task.\n\
             - If it's complex, decompose it into multiple sub-tasks.\n\
             - CRITICAL: You may ONLY use agents from the list above. Do NOT use any other agent names.\n\n\
             Return format (strict JSON, no code fences):\n\
             {{\"tasks\": [{{\"id\": \"t1\", \"agent\": \"<agent_name>\", \"prompt\": \"<detailed prompt for the agent>\", \"description\": \"<short description>\", \"depends_on\": []}}]}}\n\n\
             Rules:\n\
             - Give each task a short id like t1, t2, t3\n\
             - Use depends_on to specify dependencies (empty array if none)\n\
             - Tasks that CAN run in parallel SHOULD have independent dependencies\n\
             - Assign each sub-task to the most appropriate agent\n\
             - Prompts should be self-contained and detailed\n\
             - CRITICAL: Each agent works in an isolated git worktree. Do NOT assign tasks that \
             modify the same files to different agents.\n\
             - EVEN FOR SIMPLE REQUESTS: You must still return the JSON format above with at least one task.\n\
             - NEVER respond with plain text. ALWAYS respond with JSON.",
            agent_list.join("\n"),
            prompt
        )
    }

    /// Build a prompt for the master agent to review worker results.
    pub fn build_review_prompt(
        original_prompt: &str,
        worker_results: &[WorkerResult],
    ) -> String {
        let result_sections: Vec<String> = worker_results
            .iter()
            .map(|r| {
                format!(
                    "### {} (exit code: {})\n{}",
                    r.agent, r.exit_code, r.output_summary
                )
            })
            .collect();

        format!(
            "You are reviewing the results of a multi-agent task.\n\n\
             Original task: {}\n\n\
             Worker results:\n{}\n\n\
             Please:\n\
             1. Summarize what each worker accomplished\n\
             2. Identify any conflicts or issues between outputs\n\
             3. Provide a final integration summary\n\
             4. Note any tasks that failed and suggest remediation",
            original_prompt,
            result_sections.join("\n\n")
        )
    }

    /// Build the master agent's prompt that includes task decomposition instructions.
    // Planned for future use: alternative orchestration flow.
    #[allow(dead_code)]
    pub fn build_master_prompt(prompt: &str, agents: &[AgentConfig]) -> String {
        let worker_list: Vec<String> = agents
            .iter()
            .filter(|a| !a.is_master)
            .map(|a| {
                format!(
                    "- {} (x{} sub-agents)",
                    a.tool_name, a.sub_agent_count
                )
            })
            .collect();

        format!(
            "You are the master orchestrator agent. Your task is to coordinate and review the work \
             of the following worker agents:\n\
             {}\n\n\
             Original task: {}\n\n\
             Instructions:\n\
             1. Break down the original task into sub-tasks for each worker agent.\n\
             2. Monitor the progress of each sub-task.\n\
             3. Review and integrate the results from all worker agents.\n\
             4. Ensure consistency and resolve any conflicts between the outputs.\n\
             5. Provide a final summary of the completed work.",
            worker_list.join("\n"),
            prompt
        )
    }

    /// Prompt sent to master when a worker asks a question.
    pub fn build_question_relay_prompt(worker_agent: &str, question: &str) -> String {
        format!(
            r#"Worker agent "{}" is asking the following question:

{}

If you can answer this confidently, respond with just your answer.
If you need the user's input, respond with exactly this JSON format:
{{"ask_user": "<your question for the user>"}}"#,
            worker_agent, question
        )
    }

    /// Prompt sent to master for context backup before /clear.
    pub fn build_context_backup_prompt() -> String {
        r#"Back up all context from this session. Write a comprehensive summary including:
- Original task and sub-tasks assigned
- What each worker agent accomplished and their results
- Which files were changed
- Open questions or remaining work
- Key decisions and their rationale

Respond with exactly this JSON format:
{"context_backup": "<your markdown summary>"}"#.to_string()
    }

    /// Prompt sent to new master to restore context after /clear.
    pub fn build_context_restore_prompt(context_md: &str, new_prompt: &str) -> String {
        format!(
            r#"Previous session context is below. Read and remember it, then proceed to the new task.

{}

---
New task: {}"#,
            context_md, new_prompt
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn create_plan_creates_empty_shell() {
        let config = OrchestratorConfig {
            agents: vec![
                AgentConfig {
                    tool_name: "claude".to_string(),
                    sub_agent_count: 1,
                    is_master: true,
                },
                AgentConfig {
                    tool_name: "gemini".to_string(),
                    sub_agent_count: 1,
                    is_master: false,
                },
            ],
            master_agent: "claude".to_string(),
        };

        let plan = Orchestrator::create_plan("refactor auth module", &config);
        assert!(plan.sub_tasks.is_empty());
        assert_eq!(plan.master_agent, "claude");
        assert_eq!(plan.original_prompt, "refactor auth module");
        assert_eq!(plan.phase, OrchestrationPhase::Decomposing);
        assert!(plan.decomposition.is_none());
        assert!(plan.worker_results.is_empty());
    }

    #[test]
    fn master_prompt_includes_workers() {
        let agents = vec![
            AgentConfig {
                tool_name: "claude".to_string(),
                sub_agent_count: 1,
                is_master: true,
            },
            AgentConfig {
                tool_name: "gemini".to_string(),
                sub_agent_count: 2,
                is_master: false,
            },
        ];

        let prompt = Orchestrator::build_master_prompt("fix bugs", &agents);
        assert!(prompt.contains("gemini"));
        assert!(prompt.contains("fix bugs"));
        assert!(prompt.contains("master orchestrator"));
    }

    #[test]
    fn decompose_prompt_includes_agents_and_task() {
        let agents = vec![
            AgentConfig { tool_name: "claude".to_string(), sub_agent_count: 1, is_master: true },
            AgentConfig { tool_name: "gemini".to_string(), sub_agent_count: 1, is_master: false },
        ];
        let prompt = Orchestrator::build_decompose_prompt("refactor auth", &agents);
        assert!(prompt.contains("gemini"));
        assert!(prompt.contains("claude"));
        assert!(prompt.contains("refactor auth"));
        assert!(prompt.contains("JSON"));
        assert!(prompt.contains("depends_on"));
    }

    #[test]
    fn review_prompt_includes_worker_results() {
        let results = vec![WorkerResult {
            task_id: "t1".to_string(),
            agent: "gemini".to_string(),
            exit_code: 0,
            output_summary: "Analysis complete".to_string(),
            retry_count: 0,
            original_agent: None,
            failure_reason: None,
        }];
        let prompt = Orchestrator::build_review_prompt("fix bugs", &results);
        assert!(prompt.contains("fix bugs"));
        assert!(prompt.contains("gemini"));
        assert!(prompt.contains("Analysis complete"));
    }

    #[test]
    fn test_orchestration_phase_has_waiting_for_input() {
        let phase = OrchestrationPhase::WaitingForInput;
        let json = serde_json::to_string(&phase).unwrap();
        assert!(json.contains("WaitingForInput"));
    }

    #[test]
    fn test_orchestration_plan_has_master_process_id() {
        let config = OrchestratorConfig {
            agents: vec![],
            master_agent: "claude".to_string(),
        };
        let plan = Orchestrator::create_plan("test prompt", &config);
        assert!(plan.master_process_id.is_none());
    }

    #[test]
    fn test_pending_question_struct() {
        let entry = PendingQuestion {
            question: crate::adapters::Question {
                source_agent: "codex".to_string(),
                content: "Which DB?".to_string(),
                question_type: crate::adapters::QuestionType::Clarification,
            },
            worker_task_id: "task-123".to_string(),
            plan_id: "plan-1".to_string(),
        };
        assert_eq!(entry.worker_task_id, "task-123");
        assert_eq!(entry.plan_id, "plan-1");
    }

    #[test]
    fn test_build_question_relay_prompt() {
        let prompt = Orchestrator::build_question_relay_prompt("codex", "Which DB?");
        assert!(prompt.contains("codex"));
        assert!(prompt.contains("Which DB?"));
        assert!(prompt.contains("ask_user"));
    }

    #[test]
    fn test_build_context_backup_prompt() {
        let prompt = Orchestrator::build_context_backup_prompt();
        assert!(prompt.contains("context_backup"));
        assert!(prompt.contains("comprehensive summary"));
    }

    #[test]
    fn test_build_context_restore_prompt() {
        let prompt = Orchestrator::build_context_restore_prompt("prev context here", "new task");
        assert!(prompt.contains("prev context here"));
        assert!(prompt.contains("new task"));
        assert!(prompt.contains("Previous session context"));
    }

    // === Integration tests: cross-module data structure verification ===

    #[test]
    fn test_full_plan_lifecycle() {
        let config = OrchestratorConfig {
            agents: vec![
                AgentConfig {
                    tool_name: "claude".to_string(),
                    sub_agent_count: 1,
                    is_master: true,
                },
                AgentConfig {
                    tool_name: "gemini".to_string(),
                    sub_agent_count: 1,
                    is_master: false,
                },
            ],
            master_agent: "claude".to_string(),
        };
        let plan = Orchestrator::create_plan("optimize code", &config);
        assert!(plan.master_process_id.is_none());
        assert_eq!(plan.phase, OrchestrationPhase::Decomposing);
        assert!(plan.sub_tasks.is_empty());
        assert!(plan.decomposition.is_none());
        assert!(plan.worker_results.is_empty());
        assert_eq!(plan.master_agent, "claude");
    }

    #[test]
    fn test_decomposition_result_parsing() {
        let json = r#"{"tasks":[{"agent":"codex","prompt":"analyze","description":"analyze code"}]}"#;
        let result: DecompositionResult = serde_json::from_str(json).unwrap();
        assert_eq!(result.tasks.len(), 1);
        assert_eq!(result.tasks[0].agent, "codex");
        assert_eq!(result.tasks[0].prompt, "analyze");
        assert_eq!(result.tasks[0].description, "analyze code");
    }

    #[test]
    fn test_ask_user_response_parsing() {
        use crate::adapters::AskUserResponse;
        let json = r#"{"ask_user": "Which database schema?"}"#;
        let resp: AskUserResponse = serde_json::from_str(json).unwrap();
        assert_eq!(resp.ask_user, "Which database schema?");
    }

    #[test]
    fn test_all_prompt_builders_combined() {
        let q = Orchestrator::build_question_relay_prompt("codex", "Which DB?");
        assert!(q.contains("codex") && q.contains("ask_user"));

        let b = Orchestrator::build_context_backup_prompt();
        assert!(b.contains("context_backup"));

        let r = Orchestrator::build_context_restore_prompt("old context", "new task");
        assert!(r.contains("old context") && r.contains("new task"));

        let agents = vec![
            AgentConfig { tool_name: "claude".to_string(), sub_agent_count: 1, is_master: true },
            AgentConfig { tool_name: "gemini".to_string(), sub_agent_count: 1, is_master: false },
        ];
        let d = Orchestrator::build_decompose_prompt("fix auth", &agents);
        assert!(d.contains("fix auth") && d.contains("JSON"));

        let results = vec![WorkerResult {
            task_id: "t1".to_string(),
            agent: "gemini".to_string(),
            exit_code: 0,
            output_summary: "Done".to_string(),
            retry_count: 0,
            original_agent: None,
            failure_reason: None,
        }];
        let rv = Orchestrator::build_review_prompt("fix auth", &results);
        assert!(rv.contains("fix auth") && rv.contains("Done"));
    }

    #[test]
    fn test_decomposition_result_with_depends_on() {
        let json = r#"{"tasks":[
            {"agent":"claude","prompt":"create schema","description":"DB schema","depends_on":[]},
            {"agent":"gemini","prompt":"build api","description":"API endpoints","depends_on":["t1"]}
        ]}"#;
        let result: DecompositionResult = serde_json::from_str(json).unwrap();
        assert_eq!(result.tasks.len(), 2);
        assert!(result.tasks[0].depends_on.is_empty());
        assert_eq!(result.tasks[1].depends_on, vec!["t1"]);
    }

    #[test]
    fn test_pending_question_with_adapter_question() {
        let pq = PendingQuestion {
            question: crate::adapters::Question {
                source_agent: "gemini".to_string(),
                content: "Need clarification".to_string(),
                question_type: crate::adapters::QuestionType::Clarification,
            },
            worker_task_id: "worker-1".to_string(),
            plan_id: "plan-x".to_string(),
        };
        assert_eq!(pq.worker_task_id, "worker-1");
        assert_eq!(pq.question.source_agent, "gemini");
        assert_eq!(pq.question.content, "Need clarification");
        assert!(matches!(pq.question.question_type, crate::adapters::QuestionType::Clarification));
    }

    #[test]
    fn test_worker_result_with_retry_info() {
        let result = WorkerResult {
            task_id: "t1".to_string(),
            agent: "gemini".to_string(),
            exit_code: 0,
            output_summary: "Done".to_string(),
            retry_count: 1,
            original_agent: Some("claude".to_string()),
            failure_reason: Some("Rate limited".to_string()),
        };
        assert_eq!(result.retry_count, 1);
        assert_eq!(result.original_agent.unwrap(), "claude");
        assert_eq!(result.failure_reason.unwrap(), "Rate limited");
    }
}

use serde::Serialize;
use specta::Type;
use std::path::PathBuf;

#[derive(Debug, Clone, Serialize, Type)]
pub struct WorktreeEntry {
    pub task_id: String,
    pub worktree_name: String,
    pub branch_name: String,
    pub path: PathBuf,
    /// ISO 8601 timestamp string (specta does not implement Type for chrono::DateTime)
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Type)]
pub struct ConflictFile {
    pub path: String,
}

#[derive(Debug, Clone, Serialize, Type)]
pub struct ConflictReport {
    pub has_conflicts: bool,
    pub conflicting_files: Vec<ConflictFile>,
    pub worktree_a: String,
    pub worktree_b: String,
}

#[derive(Debug, Clone, Serialize, Type)]
pub struct FileDiff {
    pub path: String,
    pub status: String,
    pub old_path: Option<String>,
    pub patch: String,
    pub additions: u32,
    pub deletions: u32,
}

#[derive(Debug, Clone, Serialize, Type)]
pub struct WorktreeDiffReport {
    pub branch_name: String,
    pub default_branch: String,
    pub files: Vec<FileDiff>,
    pub total_additions: u32,
    pub total_deletions: u32,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn worktree_entry_serializes_all_fields() {
        let entry = WorktreeEntry {
            task_id: "abc12345-def6-7890".to_string(),
            worktree_name: "whalecode-abc12345".to_string(),
            branch_name: "whalecode/task/abc12345".to_string(),
            path: PathBuf::from("/tmp/.whalecode-worktrees/whalecode-abc12345"),
            created_at: chrono::Utc::now().to_rfc3339(),
        };

        let json = serde_json::to_value(&entry).expect("should serialize");
        assert!(json.get("task_id").is_some());
        assert!(json.get("worktree_name").is_some());
        assert!(json.get("branch_name").is_some());
        assert!(json.get("path").is_some());
        assert!(json.get("created_at").is_some());
        assert_eq!(json["task_id"], "abc12345-def6-7890");
        assert_eq!(json["worktree_name"], "whalecode-abc12345");
        assert_eq!(json["branch_name"], "whalecode/task/abc12345");
    }

    #[test]
    fn conflict_file_serializes_with_path() {
        let file = ConflictFile {
            path: "src/main.rs".to_string(),
        };

        let json = serde_json::to_value(&file).expect("should serialize");
        assert_eq!(json["path"], "src/main.rs");
    }

    #[test]
    fn conflict_report_serializes_all_fields() {
        let report = ConflictReport {
            has_conflicts: true,
            conflicting_files: vec![
                ConflictFile {
                    path: "src/main.rs".to_string(),
                },
                ConflictFile {
                    path: "Cargo.toml".to_string(),
                },
            ],
            worktree_a: "whalecode-task-a".to_string(),
            worktree_b: "whalecode-task-b".to_string(),
        };

        let json = serde_json::to_value(&report).expect("should serialize");
        assert_eq!(json["has_conflicts"], true);
        assert_eq!(json["conflicting_files"].as_array().unwrap().len(), 2);
        assert_eq!(json["worktree_a"], "whalecode-task-a");
        assert_eq!(json["worktree_b"], "whalecode-task-b");
    }

    #[test]
    fn conflict_report_empty_conflicts() {
        let report = ConflictReport {
            has_conflicts: false,
            conflicting_files: vec![],
            worktree_a: "whalecode-task-a".to_string(),
            worktree_b: "whalecode-task-b".to_string(),
        };

        let json = serde_json::to_value(&report).expect("should serialize");
        assert_eq!(json["has_conflicts"], false);
        assert_eq!(json["conflicting_files"].as_array().unwrap().len(), 0);
    }
}

use git2::{IndexAddOption, Repository};
use std::path::Path;

use super::models::{ConflictFile, ConflictReport};

/// Detect file-level conflicts between two branches using a read-only three-way merge.
///
/// Uses `merge_trees` to simulate a merge without modifying the working directory.
/// Returns a ConflictReport indicating whether conflicts exist and which files are affected.
pub fn detect_conflicts(
    repo_path: &Path,
    branch_a: &str,
    branch_b: &str,
) -> Result<ConflictReport, String> {
    let repo = Repository::open(repo_path).map_err(|e| format!("Failed to open repo: {}", e))?;

    // Resolve both branches to commits (using find_branch to handle `/` in names)
    let commit_a = super::resolve_branch_commit(&repo, branch_a)?;
    let commit_b = super::resolve_branch_commit(&repo, branch_b)?;

    // Find merge base (common ancestor)
    let merge_base = repo
        .merge_base(commit_a.id(), commit_b.id())
        .map_err(|e| format!("No common ancestor between '{}' and '{}': {}", branch_a, branch_b, e))?;

    let ancestor_commit = repo
        .find_commit(merge_base)
        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;

    // Get trees from all three commits
    let ancestor_tree = ancestor_commit
        .tree()
        .map_err(|e| format!("Failed to get ancestor tree: {}", e))?;
    let tree_a = commit_a
        .tree()
        .map_err(|e| format!("Failed to get tree for '{}': {}", branch_a, e))?;
    let tree_b = commit_b
        .tree()
        .map_err(|e| format!("Failed to get tree for '{}': {}", branch_b, e))?;

    // Perform read-only three-way merge
    let index = repo
        .merge_trees(&ancestor_tree, &tree_a, &tree_b, None)
        .map_err(|e| format!("Failed to merge trees: {}", e))?;

    // Check for conflicts
    let has_conflicts = index.has_conflicts();
    let mut conflicting_files = Vec::new();

    if has_conflicts {
        let conflicts = index
            .conflicts()
            .map_err(|e| format!("Failed to iterate conflicts: {}", e))?;

        for entry in conflicts {
            let entry = entry.map_err(|e| format!("Failed to read conflict entry: {}", e))?;

            // Extract path from whichever side of the conflict has it
            let path = entry
                .our
                .as_ref()
                .or(entry.their.as_ref())
                .or(entry.ancestor.as_ref())
                .and_then(|e| String::from_utf8(e.path.clone()).ok());

            if let Some(path) = path {
                // Deduplicate (conflicts can appear multiple times per file)
                if !conflicting_files.iter().any(|f: &ConflictFile| f.path == path) {
                    conflicting_files.push(ConflictFile { path });
                }
            }
        }
    }

    Ok(ConflictReport {
        has_conflicts,
        conflicting_files,
        worktree_a: branch_a.to_string(),
        worktree_b: branch_b.to_string(),
    })
}

/// Perform a dry-run merge check using `git merge --no-commit --no-ff` via Command.
///
/// This is a more thorough conflict check than `detect_conflicts` because it
/// simulates the actual merge operation git would perform, including index-level
/// checks. After the check, any merge state is cleaned up via `git merge --abort`.
///
/// Returns a list of conflicting file paths, or an empty vec if clean.
pub fn dry_run_merge_check(
    repo_path: &Path,
    branch_name: &str,
) -> Result<Vec<String>, String> {
    use std::process::Command;

    // Run git merge --no-commit --no-ff to simulate the merge
    let output = Command::new("git")
        .args(["merge", "--no-commit", "--no-ff", branch_name])
        .current_dir(repo_path)
        .output()
        .map_err(|e| format!("Failed to run git merge dry-run: {}", e))?;

    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);

    if output.status.success() {
        // Merge succeeded without conflicts — abort to restore original state
        let _ = Command::new("git")
            .args(["merge", "--abort"])
            .current_dir(repo_path)
            .output();
        // Also try reset in case --abort doesn't work (merge was successful)
        let _ = Command::new("git")
            .args(["reset", "--merge"])
            .current_dir(repo_path)
            .output();
        return Ok(Vec::new());
    }

    // Parse conflicting files from the output
    let mut conflicting_files = Vec::new();
    let combined = format!("{}\n{}", stdout, stderr);
    for line in combined.lines() {
        // Git outputs "CONFLICT (content): Merge conflict in <file>"
        if let Some(rest) = line.strip_prefix("CONFLICT") {
            if let Some(idx) = rest.find("Merge conflict in ") {
                let file = rest[idx + "Merge conflict in ".len()..].trim();
                if !file.is_empty() {
                    conflicting_files.push(file.to_string());
                }
            }
            // Also handle "CONFLICT (modify/delete): <file> deleted in ..."
            // and other CONFLICT patterns where the file appears after ):
            else if let Some(after_paren) = rest.strip_prefix(" (") {
                if let Some(close_idx) = after_paren.find("): ") {
                    let after = &after_paren[close_idx + 3..];
                    // The file path is typically the first word
                    let file = after.split_whitespace().next().unwrap_or("");
                    if !file.is_empty() && !conflicting_files.contains(&file.to_string()) {
                        conflicting_files.push(file.to_string());
                    }
                }
            }
        }
    }

    // Abort the merge to restore original state
    let _ = Command::new("git")
        .args(["merge", "--abort"])
        .current_dir(repo_path)
        .output();

    Ok(conflicting_files)
}

/// Auto-commit all uncommitted changes in a worktree with a standard message.
///
/// Returns Ok(true) if changes were committed, Ok(false) if the worktree was clean.
pub fn auto_commit_worktree(worktree_path: &Path) -> Result<bool, String> {
    let repo =
        Repository::open(worktree_path).map_err(|e| format!("Failed to open repo: {}", e))?;

    // Check if there are any changes (modified, new, deleted)
    let statuses = repo
        .statuses(None)
        .map_err(|e| format!("Failed to get repo status: {}", e))?;

    let has_changes = statuses.iter().any(|s| {
        !s.status().is_ignored()
            && (s.status().intersects(
                git2::Status::WT_MODIFIED
                    | git2::Status::WT_NEW
                    | git2::Status::WT_DELETED
                    | git2::Status::WT_RENAMED
                    | git2::Status::WT_TYPECHANGE
                    | git2::Status::INDEX_MODIFIED
                    | git2::Status::INDEX_NEW
                    | git2::Status::INDEX_DELETED
                    | git2::Status::INDEX_RENAMED
                    | git2::Status::INDEX_TYPECHANGE,
            ))
    });

    if !has_changes {
        return Ok(false);
    }

    // Stage all changes
    let mut index = repo.index().map_err(|e| format!("Failed to get index: {}", e))?;
    index
        .add_all(["*"].iter(), IndexAddOption::DEFAULT, None)
        .map_err(|e| format!("Failed to stage changes: {}", e))?;
    index
        .write()
        .map_err(|e| format!("Failed to write index: {}", e))?;

    // Write tree from index
    let tree_id = index
        .write_tree()
        .map_err(|e| format!("Failed to write tree: {}", e))?;
    let tree = repo
        .find_tree(tree_id)
        .map_err(|e| format!("Failed to find tree: {}", e))?;

    // Create commit
    let sig = git2::Signature::now("WhaleCode", "whalecode@auto")
        .map_err(|e| format!("Failed to create signature: {}", e))?;
    let parent = repo
        .head()
        .map_err(|e| format!("Failed to get HEAD: {}", e))?
        .peel_to_commit()
        .map_err(|e| format!("Failed to peel HEAD: {}", e))?;

    repo.commit(
        Some("HEAD"),
        &sig,
        &sig,
        "whalecode: auto-commit task changes",
        &tree,
        &[&parent],
    )
    .map_err(|e| format!("Failed to create commit: {}", e))?;

    Ok(true)
}

